def _decompose_address(self, addr):
    offset = addr & ((1 << self.config.offset_bits) - 1)
    set_index = (addr >> self.config.offset_bits) & ((1 << self.config.index_bits) - 1)
    tag = addr >> (self.config.offset_bits + self.config.index_bits)
    return (tag, set_index, offset)

def lookup(self, addr):
    tag, set_index, offset = self._decompose_address(addr)
    for line in self.sets[set_index]:
        if line.valid and line.tag == tag:
            self.global_time += 1
            line.last_access = self.global_time
            return line.data[offset]
    return None

def _find_victim(self, set_index):
    cache_set = self.sets[set_index]
    for i, line in enumerate(cache_set):
        if not line.valid:
            return i
    lru_idx = 0
    lru_time = cache_set[0].last_access
    for i, line in enumerate(cache_set[1:], 1):
        if line.last_access < lru_time:
            lru_time = line.last_access
            lru_idx = i
    return lru_idx

def _load_block(self, addr, set_index, way):
    tag, _, _ = self._decompose_address(addr)
    line = self.sets[set_index][way]
    if line.valid and line.dirty:
        # Write back dirty block
        self.stats.evictions += 1
    elif line.valid:
        self.stats.evictions += 1
    block_addr = (addr >> self.config.offset_bits) << self.config.offset_bits
    for i in range(self.config.block_size):
        line.data[i] = self.backing_memory.load_byte(block_addr + i)
    self.global_time += 1
    line.valid = True
    line.tag = tag
    line.last_access = self.global_time
    line.dirty = False

def read(self, addr):
    self.stats.total_accesses += 1
    result = self.lookup(addr)
    if result is not None:
        self.stats.hits += 1
        return result
    self.stats.misses += 1
    tag, set_index, offset = self._decompose_address(addr)
    victim = self._find_victim(set_index)
    self._load_block(addr, set_index, victim)
    return self.sets[set_index][victim].data[offset]

def write(self, addr, value):
    self.stats.total_accesses += 1
    result = self.lookup(addr)
    if result is None:
        self.stats.misses += 1
        tag, set_index, offset = self._decompose_address(addr)
        victim = self._find_victim(set_index)
        self._load_block(addr, set_index, victim)
    else:
        self.stats.hits += 1
    tag, set_index, offset = self._decompose_address(addr)
    for line in self.sets[set_index]:
        if line.valid and line.tag == tag:
            line.data[offset] = value & 0xFF
            line.dirty = True
            break

# SaturatingCounter
def predict_taken(self):
    return self.state >= PredictionState.WEAKLY_TAKEN

def update(self, actually_taken):
    if actually_taken:
        if self.state < PredictionState.STRONGLY_TAKEN:
            self.state = PredictionState(self.state + 1)
    else:
        if self.state > PredictionState.STRONGLY_NOT_TAKEN:
            self.state = PredictionState(self.state - 1)

# BranchPredictor
def _get_index(self, pc):
    return (pc >> 2) % self.bht_size

def predict(self, pc):
    idx = self._get_index(pc)
    entry = self.bht[idx]
    if entry.valid and entry.tag == pc:
        taken = entry.counter.predict_taken()
        target = entry.target if taken else pc + 4
        return (taken, target)
    return (False, pc + 4)

def update(self, pc, actually_taken, actual_target):
    idx = self._get_index(pc)
    entry = self.bht[idx]
    predicted_taken = entry.counter.predict_taken() if (entry.valid and entry.tag == pc) else False
    entry.counter.update(actually_taken)
    entry.tag = pc
    entry.target = actual_target
    entry.valid = True
    self.stats.total_branches += 1
    if predicted_taken == actually_taken:
        self.stats.correct_predictions += 1
    else:
        self.stats.mispredictions += 1
    if actually_taken and predicted_taken:
        self.stats.taken_predicted_taken += 1
    elif actually_taken and not predicted_taken:
        self.stats.taken_predicted_not_taken += 1
    elif not actually_taken and predicted_taken:
        self.stats.not_taken_predicted_taken += 1
    else:
        self.stats.not_taken_predicted_not_taken += 1
